const TAG_NAME = "k78_brazier";
const COLOR_OPTIONS = [
  { label: "Blue", value: "#0000ff" },
  { label: "Green", value: "#00ff00" },
  { label: "Indigo", value: "#4b0082" },
  { label: "Orange", value: "#ffa500" },
  { label: "Red", value: "#ff0000" },
  { label: "Violet", value: "#7f00ff" },
  { label: "Yellow", value: "#ffff00" },
  { label: "White", value: "#000000" }
];

if (!globalThis.stroudDnD?.tagging?.tokens?.getTagged) {
  ui.notifications.error("stroudDnD tagging API is not available.");
  return;
}

const selectedColor = await foundry.applications.api.DialogV2.wait({
  window: { title: "Select Brazier Color" },
  content: `
    <div style="display:flex; flex-direction:column; gap:0.5rem;">
      <p style="margin:0;">Choose a light color for the tagged brazier.</p>
    </div>
  `,
  buttons: [
    ...COLOR_OPTIONS.map((option) => ({
      action: option.value,
      label: `${option.label} (${option.value})`,
      callback: () => option.value
    })),
    {
      action: "cancel",
      label: "Cancel"
    }
  ],
  rejectClose: false,
  modal: true
});

if (!selectedColor || selectedColor === "cancel") {
  return;
}

const taggedTokens = await stroudDnD.tagging.tokens.getTagged(TAG_NAME);
const tokenDocument = taggedTokens?.[0]?.document ?? taggedTokens?.[0];

if (!tokenDocument) {
  ui.notifications.warn(`No token found with tag "${TAG_NAME}".`);
  return;
}

try {
  await tokenDocument.update({ "light.color": selectedColor });
  ui.notifications.info(`${tokenDocument.name}: light color set to ${selectedColor}.`);
} catch (error) {
  console.error(error);
  ui.notifications.error(`Failed to update brazier light color: ${error.message}`);
}
